ActorListener = {}

function ActorListener:init()
    PlayerRemoveItemEvent.registerCallBack(self.onPlayerRemoveItem)
    PlayerAttackActorNpcEvent.registerCallBack(self.onPlayerAttackActorNpc)
    PlayerDropItemEvent.registerCallBack(self.onPlayerDropItem)
end

function ActorListener.onPlayerRemoveItem(rakssid, itemId, count, stackIndex)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return true
    end
    local meta
    local ArmorInv = InventoryUtil:getPlayerInventoryInfo(player)
    for _, item in pairs(ArmorInv.item) do
        if item.stackIndex == stackIndex then
            meta = item.meta
        end
    end
    local entityId = ActorManager:createItemActor(player:getPosition(), itemId, count.value, meta)
    if entityId then
        return false
    end
    return true
end

function ActorListener.onPlayerAttackActorNpc(raknetID, entityId)
    local player = PlayerManager:getPlayerByRakssid(raknetID)
    if player == nil then
        return
    end
    ActorManager:pickAttackActor(player, entityId)
    return true
end

function ActorListener.onPlayerDropItem(rakssid, itemId, itemDamage, itemCount, slot)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end
    if ActorManager:createItemActor(player:getPosition(), itemId, itemCount, itemDamage) then
        player:decrStackSize(slot, itemCount)
    end
    return false
end